const body = $json.body;
const event = {
  id: body.event_id || 'test_event_123',
  summary: body.summary || 'Weekly RevOps Sync',
  start: { dateTime: body.start || new Date(Date.now() + 7200000).toISOString() },
  end: { dateTime: body.end || new Date(Date.now() + 10800000).toISOString() },
  attendees: (body.attendees || ['ckearney@blackthorn.io']).map(e => ({ email: e })),
  description: body.description || ''
};
const attendees = event.attendees.map(a => a.email);
const domains = attendees.map(e => e.split('@')[1]).filter(d => !d.includes('gmail.com') && !d.includes('google.com'));
const startTime = new Date(event.start.dateTime);
const endTime = new Date(event.end.dateTime);
const durationMin = Math.round((endTime - startTime) / 60000);
return [{ json: {
  event_id: event.id,
  event_title: event.summary,
  meeting_datetime: event.start.dateTime,
  meeting_duration: durationMin,
  attendees: attendees.join(', '),
  attendee_domains: [...new Set(domains)],
  event_description: event.description,
  manual_notes: event.description,
  lookup_type: 'email_domain',
  lookup_value: domains[0] || 'unknown'
} }];

const eventInfo = $('Simulate Calendar Event').first().json;
const clientData = $('Client Lookup').first().json;
const openTasksRaw = $('Get Open ClickUp Tasks').first().json;
const waitingTasksRaw = $('Get Waiting on Client Tasks').first().json;
const openTasks = (openTasksRaw.tasks || []).map(t => `- [${t.priority?.priority || 'normal'}] ${t.name} (${t.status?.status || 'open'})`).join('\n') || 'No open tasks';
const waitingTasks = (waitingTasksRaw.tasks || []).map(t => `- ${t.name}`).join('\n') || 'No waiting items';
return [{ json: {
  summary: `Meeting prep for ${clientData.client_name}`,
  open_task_count: (openTasksRaw.tasks || []).length,
  waiting_task_count: (waitingTasksRaw.tasks || []).length,
  open_tasks: openTasks,
  waiting_tasks: waitingTasks,
  client_name: clientData.client_name,
  meeting_duration: eventInfo.meeting_duration
} }];
